PREFIX dcat: <http://www.w3.org/ns/dcat#>
PREFIX dct: <http://purl.org/dc/terms/>

SELECT (COUNT(?d) AS ?tot) WHERE { ?d a dcat:Dataset }

PREFIX dcat: <http://www.w3.org/ns/dcat#>
PREFIX dct: <http://purl.org/dc/terms/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX skos: <http://www.w3.org/2004/02/skos/core#>

SELECT ?dataset ?title ?publisher
WHERE {
  GRAPH ?g {
    ?dataset a dcat:Dataset ;
             dct:title ?title .
    FILTER(LANG(?title) = "en")
    FILTER(CONTAINS(LCASE(STR(?title)), "mafia"))
  }
  OPTIONAL { ?dataset dct:publisher/rdfs:label ?publisher . FILTER(LANG(?publisher)="en") }
}
LIMIT 10

PREFIX dcat: <http://www.w3.org/ns/dcat#>
PREFIX dct: <http://purl.org/dc/terms/>

SELECT ?dataset ?title ?publisher
WHERE {
  ?dataset a dcat:Dataset ;
           dct:title ?title .
  OPTIONAL { ?dataset dct:publisher ?publisher }
  ?title bif:contains "'mafia' OR 'organised crime' OR 'antimafia' OR 'criminalita organizzata'"
}
LIMIT 20

PREFIX dct: <http://purl.org/dc/terms/>
PREFIX foaf: <http://xmlns.com/foaf/0.1/>
PREFIX dcatapit: <http://dati.gov.it/onto/dcatapit#>

SELECT DISTINCT ?org ?identifier ?name WHERE {
  ?org a dcatapit:Agent ;
       dct:identifier ?identifier ;
       foaf:name ?name .
} LIMIT 100

PREFIX dcat: <http://www.w3.org/ns/dcat#>
PREFIX dct: <http://purl.org/dc/terms/>

SELECT ?dataset ?issued ?modified
WHERE {
  ?dataset a dcat:Dataset .
  FILTER(CONTAINS(STR(?dataset), "opendata.comune.palermo"))
  OPTIONAL { ?dataset dct:issued ?issued }
  OPTIONAL { ?dataset dct:modified ?modified }
}
LIMIT 10

PREFIX dct: <http://purl.org/dc/terms/>

SELECT ?dataset ?title ?lang WHERE {
  ?agent dct:identifier "00514490010" .
  ?dataset ?role ?agent .
  OPTIONAL { ?dataset dct:title ?title . BIND(LANG(?title) AS ?lang) }
}

PREFIX dct: <http://purl.org/dc/terms/>
PREFIX dcat: <http://www.w3.org/ns/dcat#>
PREFIX foaf: <http://xmlns.com/foaf/0.1/>

SELECT DISTINCT ?dataset ?title ?publisher_name ?identifier WHERE {
  ?agent foaf:name "Comune di Torino" .
  ?agent dct:identifier ?identifier .
  ?dataset ?role ?agent .
  OPTIONAL { ?dataset dct:title ?title . FILTER(LANG(?title) = "it") }
}
LIMIT 10

PREFIX dct: <http://purl.org/dc/terms/>
PREFIX dcat: <http://www.w3.org/ns/dcat#>
PREFIX foaf: <http://xmlns.com/foaf/0.1/>

SELECT ?dataset ?title ?role ?publisher_name WHERE {
  ?agent dct:identifier "c_l219" .
  ?dataset ?role ?agent .
  OPTIONAL { ?dataset dct:title ?title . FILTER(LANG(?title) = "it") }
  OPTIONAL { ?agent foaf:name ?publisher_name }
}

PREFIX dct: <http://purl.org/dc/terms/>
PREFIX dcat: <http://www.w3.org/ns/dcat#>
PREFIX foaf: <http://xmlns.com/foaf/0.1/>

SELECT ?dataset ?title ?publisher_name ?role WHERE {
  ?agent dct:identifier "c_l219" .
  ?dataset ?role ?agent .
  OPTIONAL { ?dataset dct:title ?title . FILTER(LANG(?title) = "it") }
  OPTIONAL { ?agent foaf:name ?publisher_name }
}

SELECT ?parent ?pp ?s ?p ?o WHERE {
  ?s dct:identifier "c_l219" .
  ?parent ?pp ?s .
  OPTIONAL { ?s ?p ?o }
}
PREFIX dct: <http://purl.org/dc/terms/>

PREFIX dcat: <http://www.w3.org/ns/dcat#>
PREFIX dcterms: <http://purl.org/dc/terms/>

SELECT ?datasetURI ?title ?modified
WHERE {
  <http://data.europa.eu/88u/catalogue/data-gov-gr> dcat:dataset ?datasetURI .
  ?datasetURI dcterms:title ?title .
  OPTIONAL { ?datasetURI dcterms:modified ?modified }
  FILTER(LANG(?title) = "en" || LANG(?title) = "")
}
ORDER BY DESC(?modified)

PREFIX dcat: <http://www.w3.org/ns/dcat#>
PREFIX dcterms: <http://purl.org/dc/terms/>

SELECT DISTINCT ?dataset ?title ?modified
WHERE {
  ?dataset a dcat:Dataset ;
           dcterms:title ?title .
  ?dataset dcterms:spatial <http://publications.europa.eu/resource/authority/country/GRC> .
  OPTIONAL { ?dataset dcterms:modified ?modified }
  FILTER(LANG(?title) = "en")
}
ORDER BY DESC(?modified)
LIMIT 20

PREFIX dcat: <http://www.w3.org/ns/dcat#>
PREFIX dct: <http://purl.org/dc/terms/>
PREFIX foaf: <http://xmlns.com/foaf/0.1/>
PREFIX schema: <http://schema.org/>

SELECT DISTINCT ?catalog ?title ?homepage ?country
WHERE {
  ?catalog a dcat:Catalog .
  OPTIONAL { ?catalog dct:title ?title . FILTER(LANG(?title) IN ("en", "el", "")) }
  OPTIONAL { ?catalog foaf:homepage ?homepage }
  OPTIONAL { ?catalog dct:spatial ?country }
  FILTER(CONTAINS(STR(?country), "GRC") || CONTAINS(STR(?country), "greece") || CONTAINS(LCASE(STR(?title)), "greece") || CONTAINS(LCASE(STR(?title)), "greek") || CONTAINS(LCASE(STR(?title)), "ellas") || CONTAINS(LCASE(STR(?title)), "hellas"))
}
LIMIT 50

PREFIX dcat: <http://www.w3.org/ns/dcat#>
PREFIX dcterms: <http://purl.org/dc/terms/>

SELECT ?dataset ?title ?modified
WHERE {
  ?dataset dcterms:title ?title ;
           dcat:inCatalog <http://data.europa.eu/88u/catalogue/data-gov-gr> .
  OPTIONAL { ?dataset dcterms:modified ?modified }
  FILTER(LANG(?title) = "en" || LANG(?title) = "")
}
ORDER BY DESC(?modified)
LIMIT 15

PREFIX dcat: <http://www.w3.org/ns/dcat#>
PREFIX dcterms: <http://purl.org/dc/terms/>
PREFIX adms: <http://www.w3.org/ns/adms#>

SELECT ?dataset ?title ?issued ?modified ?format
WHERE {
  ?dataset dcat:catalog <http://data.europa.eu/88u/catalogue/data-gov-gr> ;
           dcterms:title ?title .
  OPTIONAL { ?dataset dcterms:issued ?issued }
  OPTIONAL { ?dataset dcterms:modified ?modified }
  FILTER(LANG(?title) = "en" || LANG(?title) = "")
}
ORDER BY DESC(?modified)
LIMIT 15

PREFIX dcat: <http://www.w3.org/ns/dcat#>
PREFIX dcterms: <http://purl.org/dc/terms/>
PREFIX schema: <http://schema.org/>

SELECT ?catalog ?datasetCount ?modified ?publisher
WHERE {
  VALUES ?catalog { 
    <http://data.europa.eu/88u/catalogue/ypes>
    <http://data.europa.eu/88u/catalogue/data-gov-gr>
  }
  OPTIONAL {
    SELECT ?catalog (COUNT(DISTINCT ?dataset) AS ?datasetCount)
    WHERE { ?catalog dcat:dataset ?dataset }
    GROUP BY ?catalog
  }
  OPTIONAL { ?catalog dcterms:modified ?modified }
  OPTIONAL { ?catalog dcterms:publisher ?publisherNode . ?publisherNode schema:name ?publisher }
}

PREFIX dcat: <http://www.w3.org/ns/dcat#>
PREFIX dcterms: <http://purl.org/dc/terms/>
PREFIX foaf: <http://xmlns.com/foaf/0.1/>

SELECT DISTINCT ?catalog ?title ?homepage ?description
WHERE {
  ?catalog a dcat:Catalog ;
           dcterms:title ?title ;
           dcterms:spatial <http://publications.europa.eu/resource/authority/country/GRC> .
  OPTIONAL { ?catalog foaf:homepage ?homepage }
  OPTIONAL { ?catalog dcterms:description ?description . FILTER(LANG(?description) = "en") }
  FILTER(LANG(?title) = "en" || LANG(?title) = "")
}

PREFIX dcat: <http://www.w3.org/ns/dcat#>
PREFIX dcterms: <http://purl.org/dc/terms/>
PREFIX foaf: <http://xmlns.com/foaf/0.1/>
PREFIX schema: <http://schema.org/>

SELECT ?catalog ?title ?homepage ?datasetCount
WHERE {
  ?catalog a dcat:Catalog ;
           dcterms:title ?title .
  OPTIONAL { ?catalog foaf:homepage ?homepage }
  OPTIONAL { ?catalog dcat:dataset ?dataset }
  ?catalog dcterms:spatial ?spatial .
  FILTER(?spatial = <http://publications.europa.eu/resource/authority/country/GRC>)
  FILTER(LANG(?title) = "en" || LANG(?title) = "el" || LANG(?title) = "")
}

PREFIX dcat: <http://www.w3.org/ns/dcat#>
PREFIX dct: <http://purl.org/dc/terms/>
PREFIX foaf: <http://xmlns.com/foaf/0.1/>

SELECT DISTINCT ?catalog ?title ?homepage
WHERE {
  ?catalog a dcat:Catalog .
  ?catalog dct:spatial <http://publications.europa.eu/resource/authority/country/GRC> .
  OPTIONAL { ?catalog dct:title ?title . FILTER(LANG(?title) = "en") }
  OPTIONAL { ?catalog foaf:homepage ?homepage }
}
LIMIT 50

PREFIX dcat: <http://www.w3.org/ns/dcat#>
PREFIX dct: <http://purl.org/dc/terms/>
PREFIX foaf: <http://xmlns.com/foaf/0.1/>
PREFIX schema: <http://schema.org/>

SELECT DISTINCT ?catalog ?title ?homepage ?description
WHERE {
  ?catalog a dcat:Catalog .
  ?catalog dct:spatial ?spatial .
  FILTER(CONTAINS(STR(?spatial), "EL") || CONTAINS(STR(?spatial), "greece") || CONTAINS(STR(?spatial), "GRC"))
  OPTIONAL { ?catalog dct:title ?title . FILTER(LANG(?title) = "en" || LANG(?title) = "el" || LANG(?title) = "") }
  OPTIONAL { ?catalog foaf:homepage ?homepage }
  OPTIONAL { ?catalog dct:description ?description . FILTER(LANG(?description) = "en") }
}
LIMIT 50

