SELECT (COUNT(DISTINCT ?dataset) AS ?count)
WHERE {
  GRAPH <http://data.europa.eu/88u/graph/eudp> {
    ?dataset a dcat:Dataset ;
             dct:title ?title .
    FILTER(CONTAINS(LCASE(STR(?title)), "violence"))
