SELECT (COUNT(DISTINCT ?dataset) AS ?count)
WHERE {
  ?dataset a dcat:Dataset ;
           dct:title ?title .
  FILTER(REGEX(STR(?title), "violenc|violenza|violencia|gewalt", "i"))
}

PREFIX dcat: <http://www.w3.org/ns/dcat#>
PREFIX dct: <http://purl.org/dc/terms/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>

SELECT (COUNT(DISTINCT ?dataset) AS ?count)
WHERE {
  ?dataset a dcat:Dataset .
  {
    ?dataset dct:title ?title .
    FILTER(LANG(?title) IN ("it","en","fr","de","es"))
    FILTER(REGEX(STR(?title), "violenz|violence|violencia|violência|gewalt", "i"))
  }
  UNION
  {
    ?dataset dcat:keyword ?kw .
    FILTER(REGEX(STR(?kw), "violenz|violence|violencia|violência|gewalt", "i"))
  }
}

