PREFIX dcat: <http://www.w3.org/ns/dcat#>
PREFIX dct: <http://purl.org/dc/terms/>
PREFIX foaf: <http://xmlns.com/foaf/0.1/>

SELECT ?title ?publisher ?format WHERE {
  ?dataset a dcat:Dataset ;
           dct:title ?title ;
           dct:publisher ?pub ;
           dcat:distribution ?dist .
  ?pub foaf:name ?publisher .
  ?dist dct:format ?format .
  FILTER(LANG(?title) = "it")
  FILTER(CONTAINS(LCASE(STR(?title)), "confini"))
  FILTER(CONTAINS(LCASE(STR(?format)), "geojson") || CONTAINS(LCASE(STR(?format)), "shp"))
}
LIMIT 10

